var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"CN No. VCDF001D003526-63\\n<color=#ffd34c>1급 요인</color> 열람 승인 자료\\n부록: ████ 경찰청 회의실 도청 녹취록","JPN":"CN No. VCDF001D003526-63\\n<color=#ffd34c>1級要因</color> 閲覧承認資料\\n付録: ████警察庁会議室盗聴録音記録","ENG":"(ENG)CN No. VCDF001D003526-63\\n<color=#ffd34c>1급 요인</color> 열람 승인 자료\\n부록: ████ 경찰청 회의실 도청 녹취록","TWN":"(TWN)CN No. VCDF001D003526-63\\n<color=#ffd34c>1급 요인</color> 열람 승인 자료\\n부록: ████ 경찰청 회의실 도청 녹취록"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"자, 다들 주목.","JPN":"さあ、みんな注目。","ENG":"(ENG)자, 다들 주목.","TWN":"(TWN)자, 다들 주목."},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"갑자기 소집령이 떨어져서 다들 피곤하겠지만 졸진 마라.\\n너 말이다, 너. 윈터슨.","JPN":"急に召集令が離れて立ってみんな疲れるがまどろむかはないで。\\n君言葉である、君。ウィントスン。","ENG":"(ENG)갑자기 소집령이 떨어져서 다들 피곤하겠지만 졸진 마라.\\n너 말이다, 너. 윈터슨.","TWN":"(TWN)갑자기 소집령이 떨어져서 다들 피곤하겠지만 졸진 마라.\\n너 말이다, 너. 윈터슨."},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"인터폴로부터 협조 요청을 받은 적색수배자가 우리 관할지에서 발견됐다는 소식이다.","JPN":"インターポールから協調要請を受けた赤色お尋ね者が私たちの管轄地で発見されたという消息である。","ENG":"(ENG)인터폴로부터 협조 요청을 받은 적색수배자가 우리 관할지에서 발견됐다는 소식이다.","TWN":"(TWN)인터폴로부터 협조 요청을 받은 적색수배자가 우리 관할지에서 발견됐다는 소식이다."},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"이름은 베네딕트 콘스탄틴.","JPN":"名前はベネディクト・コンスタンティン。","ENG":"(ENG)이름은 베네딕트 콘스탄틴.","TWN":"(TWN)이름은 베네딕트 콘스탄틴."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"네이티브 아메리칸 혼혈로, 사제 서품을 받은 이력이 있다.","JPN":"ネイティブアメリカン混血で、師弟叙階を受けた履歴がある。","ENG":"(ENG)네이티브 아메리칸 혼혈로, 사제 서품을 받은 이력이 있다.","TWN":"(TWN)네이티브 아메리칸 혼혈로, 사제 서품을 받은 이력이 있다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 지금까지 127명이나 되는 사상자를 만든 위험한 녀석이지.","JPN":"そして今まで127人もなる死傷者を作った危ないやつだ。","ENG":"(ENG)그리고 지금까지 127명이나 되는 사상자를 만든 위험한 녀석이지.","TWN":"(TWN)그리고 지금까지 127명이나 되는 사상자를 만든 위험한 녀석이지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"종교적 극단주의 테러리스트와 유사한 성향으로 추정된다는 기록이 있다. 성호 그리는 법은 외워 둬.","JPN":"宗教的極端主義テロリストと類似の性向で推定されるという記録がある。城壕描く方法は覚えておく。","ENG":"(ENG)종교적 극단주의 테러리스트와 유사한 성향으로 추정된다는 기록이 있다. 성호 그리는 법은 외워 둬.","TWN":"(TWN)종교적 극단주의 테러리스트와 유사한 성향으로 추정된다는 기록이 있다. 성호 그리는 법은 외워 둬."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"마지막으로, 관리국 기준 B급 카운터이기 때문에 각별한 주의를 요하는 상황이다.","JPN":"終わりで、管理局基準B級カウンターだから格別な注意を要する状況である。","ENG":"(ENG)마지막으로, 관리국 기준 B급 카운터이기 때문에 각별한 주의를 요하는 상황이다.","TWN":"(TWN)마지막으로, 관리국 기준 B급 카운터이기 때문에 각별한 주의를 요하는 상황이다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"인터폴이 제공한 정보에 따르면, 장검술이 뛰어나고 복수의 생명체를 마비시키는 능력이 있다고 한다. ","JPN":"インターポールが提供した情報によれば、長剣術が優れていて複数の生命体を麻痺させる能力があると言う。","ENG":"(ENG)인터폴이 제공한 정보에 따르면, 장검술이 뛰어나고 복수의 생명체를 마비시키는 능력이 있다고 한다. ","TWN":"(TWN)인터폴이 제공한 정보에 따르면, 장검술이 뛰어나고 복수의 생명체를 마비시키는 능력이 있다고 한다. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"다시 말해, 놈과 눈이 마주칠 만큼 가까이 가는 건 금물이다.","JPN":"言い換えれば、やつと目が出くわすほど近くに行くのは禁物である。","ENG":"(ENG)다시 말해, 놈과 눈이 마주칠 만큼 가까이 가는 건 금물이다.","TWN":"(TWN)다시 말해, 놈과 눈이 마주칠 만큼 가까이 가는 건 금물이다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"물론 맨몸으로 카운터랑 싸우라는 건 아니니 안심하도록.","JPN":"もちろん空身でカウンターと戦うということはないから安心するように。","ENG":"(ENG)물론 맨몸으로 카운터랑 싸우라는 건 아니니 안심하도록.","TWN":"(TWN)물론 맨몸으로 카운터랑 싸우라는 건 아니니 안심하도록."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"이놈을 추격 중인 인터폴에 동일 등급 카운터 두 명이 합류해 있다고 한다.","JPN":"こいつを追撃中のインターポールに同級カウンター二人が合流していると言う。","ENG":"(ENG)이놈을 추격 중인 인터폴에 동일 등급 카운터 두 명이 합류해 있다고 한다.","TWN":"(TWN)이놈을 추격 중인 인터폴에 동일 등급 카운터 두 명이 합류해 있다고 한다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"카운터는 카운터로 상대해야지. 나대다가 2계급 특진하는 놈은 나한테 죽을 줄 알아.","JPN":"カウンターはカウンターで相対しなくてはならない。あちこち出歩いて来て2階級特進するやつは私に死ぬことができる。","ENG":"(ENG)카운터는 카운터로 상대해야지. 나대다가 2계급 특진하는 놈은 나한테 죽을 줄 알아.","TWN":"(TWN)카운터는 카운터로 상대해야지. 나대다가 2계급 특진하는 놈은 나한테 죽을 줄 알아."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"발견하면 무조건 교전을 피하고 상부의 지원을 요청할 것, 알겠나?","JPN":"見つければ無条件交戦を避けて上部の支援を要請すること、分かるか?","ENG":"(ENG)발견하면 무조건 교전을 피하고 상부의 지원을 요청할 것, 알겠나?","TWN":"(TWN)발견하면 무조건 교전을 피하고 상부의 지원을 요청할 것, 알겠나?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"브리핑은 이상이다.","JPN":"ブリーフィングは以上である。","ENG":"(ENG)브리핑은 이상이다.","TWN":"(TWN)브리핑은 이상이다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"자, 질문은 넣어 두고 어서 움직여! 어서!","JPN":"さあ、質問は入れて置いてさあ動く!語書!","ENG":"(ENG)자, 질문은 넣어 두고 어서 움직여! 어서!","TWN":"(TWN)자, 질문은 넣어 두고 어서 움직여! 어서!"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};